#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""ATLAS PG connection census (read-only, exit-0-safe). Connects as the postgres
superuser (reserved slot, immune to the exhaustion) to report exactly what is
consuming connections + how many enrich-pool units remain, so the fix is data-driven."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
def psql(q):
    for runner in (["sudo","-u","postgres","psql","-tAc",q],
                   ["su","-s","/bin/sh","postgres","-c","psql -tAc \"%s\""%q.replace('"','\\"')]):
        try:
            r=subprocess.run(runner,capture_output=True,text=True,timeout=20)
            if r.returncode==0: return r.stdout.strip()
        except Exception: pass
    return "ERR"
def sh(c):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=15); return r.stdout.strip()
    except Exception as e: return "ERR:%s"%e
out={"kind":"conncensus","ts":int(time.time())}
try:
    out["max_connections"]=psql("SHOW max_connections")
    out["reserved"]=psql("SHOW superuser_reserved_connections")
    out["total"]=psql("SELECT count(*) FROM pg_stat_activity")
    out["by_state"]=psql("SELECT coalesce(state,'null')||':'||count(*) FROM pg_stat_activity GROUP BY state ORDER BY 2 DESC")
    out["by_user"]=psql("SELECT coalesce(usename,'null')||':'||count(*) FROM pg_stat_activity GROUP BY usename ORDER BY 2 DESC")
    out["by_app"]=psql("SELECT coalesce(nullif(left(application_name,32),''),'(none)')||':'||count(*) FROM pg_stat_activity GROUP BY 1 ORDER BY 2 DESC LIMIT 25")
    out["enrich_pool_active"]=sh("systemctl list-units 'atlas-enrich-pool@*.service' --state=active --no-legend --plain 2>/dev/null | wc -l")
    out["enrich_pool_enabled"]=sh("systemctl list-unit-files 'atlas-enrich-pool@*.service' 2>/dev/null | grep -c enabled")
except Exception as e:
    out["error"]=str(e)
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN")
    repo=env.get("STATUS_REPO") or os.environ.get("STATUS_REPO","cloudwalker171/atlas-manifests")
    br=env.get("STATUS_BRANCH","main"); api="https://api.github.com"
    path="status/hetzner/conncensus.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"})
            sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"conncensus","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"})
                urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"})
                        body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
